    'color-yellow': '#FFFF00',
    'color-black': '#000000',
    'color-white': '#FFFFFF',
  };

  @override
  Widget build(BuildContext context) {
    return AlertDialog(
      title: const Text('Pick a color'),
      content: SizedBox(
        width: 240,
        child: Wrap(
