  /// Build photo widget with annotations
  Widget _buildPhotoWidget(BuildContext context, PhotoAnnotationState state) {
    return LayoutBuilder(
      builder: (context, constraints) {
        return Image.file(
          File(originalPhotoPath),
          fit: BoxFit.contain,
          frameBuilder: (context, child, frame, wasSynchronouslyLoaded) {
            if (frame != null) {
              // Calculate actual image size within constraints
              WidgetsBinding.instance.addPostFrameCallback((_) {
                _updateImageSize(context, state, constraints);
              });
