/// Provides state management for annotation tools, markers, and user interactions
library;

import 'package:flutter/material.dart';
import 'package:provider/provider.dart';
import '../../../../services/annotation_service.dart';

/// Photo annotation state management using ChangeNotifier
/// Handles annotation creation, editing, deletion, and persistence
class PhotoAnnotationState extends ChangeNotifier {
  final AnnotationService _annotationService = AnnotationService();
  final String originalPhotoPath;
  final String inspectionId;
  final String fieldId;

  // Current annotations
  List<AnnotationMarker> _annotations = [];
  AnnotationMarker? _selectedAnnotation;

  // UI state
  AnnotationType _currentTool = AnnotationType.point;
  Color _currentColor = Colors.red;
  bool _isDrawing = false;
  String? _pendingText;

  // Image dimensions for coordinate conversion
  Size? _imageSize;

  // Save state
  bool _isSaving = false;
  String? _savedAnnotatedPath;
  String? _error;

  PhotoAnnotationState({
    required this.originalPhotoPath,
    required this.inspectionId,
    required this.fieldId,
  }) {
    _loadExistingAnnotations();
  }

  /// Service locator method for accessing state
  static PhotoAnnotationState s(BuildContext context, [bool listen = false]) =>
      Provider.of<PhotoAnnotationState>(context, listen: listen);

  // Getters
  List<AnnotationMarker> get annotations => List.unmodifiable(_annotations);
  AnnotationMarker? get selectedAnnotation => _selectedAnnotation;
  AnnotationType get currentTool => _currentTool;
  Color get currentColor => _currentColor;
  bool get isDrawing => _isDrawing;
  String? get pendingText => _pendingText;
  Size? get imageSize => _imageSize;
  bool get isSaving => _isSaving;
  String? get savedAnnotatedPath => _savedAnnotatedPath;
  String? get error => _error;
  bool get hasAnnotations => _annotations.isNotEmpty;
  bool get hasUnsavedChanges => _annotations.isNotEmpty && _savedAnnotatedPath == null;

  /// Set image size for coordinate calculations
  void setImageSize(Size size) {
    _imageSize = size;
    notifyListeners();
  }

  /// Load existing annotations if available
  Future<void> _loadExistingAnnotations() async {
    try {
      // Check if annotated version exists
      final annotatedPhotos = await _annotationService.getAnnotatedPhotos(inspectionId);
      final existingAnnotated = annotatedPhotos
          .where((path) => path.contains(fieldId))
          .firstOrNull;

      if (existingAnnotated != null) {
        _savedAnnotatedPath = existingAnnotated;
        _annotations = await _annotationService.loadAnnotationMetadata(existingAnnotated);
        notifyListeners();
      }
    } catch (e) {
      _error = 'Failed to load existing annotations: ${e.toString()}';
      notifyListeners();
    }
  }

  /// Add annotation at the given position
  void addAnnotation(Offset position) {
    if (_imageSize == null) return;

    // Convert screen coordinates to normalized coordinates
    final normalizedPosition = Offset(
      position.dx / _imageSize!.width,
      position.dy / _imageSize!.height,
    );

    final annotation = AnnotationMarker(
      id: DateTime.now().millisecondsSinceEpoch.toString(),
      type: _currentTool,
      position: normalizedPosition,
      color: _currentColor,
      text: _currentTool == AnnotationType.text ? _pendingText : null,
      size: _getDefaultSize(),
    );

    _annotations.add(annotation);
    _selectedAnnotation = annotation;
    _pendingText = null;
    notifyListeners();
  }

  /// Get default size for shape annotations
  Size? _getDefaultSize() {
    switch (_currentTool) {
      case AnnotationType.rectangle:
        return const Size(0.1, 0.08); // 10% width, 8% height
      case AnnotationType.circle:
        return const Size(0.08, 0.08); // 8% diameter
      default:
        return null;
    }
  }

  /// Select annotation
  void selectAnnotation(AnnotationMarker? annotation) {
    _selectedAnnotation = annotation;
    notifyListeners();
  }

  /// Update selected annotation
  void updateSelectedAnnotation({
    Offset? position,
    Color? color,
    String? label,
    String? text,
    double? direction,
    Size? size,
  }) {
    if (_selectedAnnotation == null) return;

    final updatedAnnotation = _selectedAnnotation!.copyWith(
      position: position,
      color: color,
      label: label,
      text: text,
      direction: direction,
      size: size,
    );

    final index = _annotations.indexOf(_selectedAnnotation!);
    _annotations[index] = updatedAnnotation;
    _selectedAnnotation = updatedAnnotation;
    notifyListeners();
  }

  /// Delete annotation
  void deleteAnnotation(AnnotationMarker annotation) {
    _annotations.remove(annotation);
    if (_selectedAnnotation == annotation) {
      _selectedAnnotation = null;
    }
    notifyListeners();
  }

  /// Delete selected annotation
  void deleteSelectedAnnotation() {
    if (_selectedAnnotation != null) {
      deleteAnnotation(_selectedAnnotation!);
    }
  }

  /// Set current tool
  void setCurrentTool(AnnotationType tool) {
    _currentTool = tool;
    _selectedAnnotation = null;
    notifyListeners();
  }

  /// Set current color
  void setCurrentColor(Color color) {
    _currentColor = color;
    notifyListeners();
  }

  /// Set pending text for text annotations
