    _pendingText = text;
    notifyListeners();
  }

  /// Start drawing mode
  void startDrawing() {
    _isDrawing = true;
    notifyListeners();
  }

  /// Stop drawing mode
  void stopDrawing() {
    _isDrawing = false;
    notifyListeners();
