class AnnotationPainter extends CustomPainter {
  final List<AnnotationMarker> annotations;
  final AnnotationMarker? selectedAnnotation;
  final Size imageSize;

  AnnotationPainter({
    required this.annotations,
    required this.selectedAnnotation,
    required this.imageSize,
  });

  @override
  void paint(Canvas canvas, Size size) {
    for (final annotation in annotations) {
      _drawAnnotation(canvas, annotation, size);
    }

    // Draw selection indicator
    if (selectedAnnotation != null) {
      _drawSelectionIndicator(canvas, selectedAnnotation!, size);
    }
  }

  void _drawAnnotation(Canvas canvas, AnnotationMarker annotation, Size size) {
    final paint = Paint()
      ..color = annotation.color
      ..strokeWidth = annotation.strokeWidth
      ..style = PaintingStyle.fill;

    final strokePaint = Paint()
      ..color = Colors.white
      ..strokeWidth = annotation.strokeWidth + 2
      ..style = PaintingStyle.stroke;

    final position = Offset(
      annotation.position.dx * size.width,
      annotation.position.dy * size.height,
    );

    switch (annotation.type) {
      case AnnotationType.point:
        canvas.drawCircle(position, 10, strokePaint);
        canvas.drawCircle(position, 8, paint);
        break;

      case AnnotationType.arrow:
        _drawArrow(canvas, position, annotation.direction ?? 0, paint, strokePaint);
        break;

      case AnnotationType.rectangle:
        if (annotation.size != null) {
          final rect = Rect.fromCenter(
            center: position,
            width: annotation.size!.width * size.width,
            height: annotation.size!.height * size.height,
          );
          canvas.drawRect(rect, strokePaint);
          canvas.drawRect(rect, paint..style = PaintingStyle.stroke);
        }
        break;

      case AnnotationType.circle:
        final radius = (annotation.size?.width ?? 0.05) * size.width / 2;
        canvas.drawCircle(position, radius + 2, strokePaint);
        canvas.drawCircle(position, radius, paint..style = PaintingStyle.stroke);
        break;

      case AnnotationType.text:
        if (annotation.text != null) {
          _drawText(canvas, position, annotation.text!, annotation.color);
        }
        break;
    }
  }

  void _drawArrow(Canvas canvas, Offset position, double direction, Paint paint, Paint strokePaint) {
    // Simple arrow implementation
    canvas.drawCircle(position, 8, strokePaint);
    canvas.drawCircle(position, 6, paint);
  }

