class SyncStatusSnapshot {
  final SyncStatus status;
  final int processed;
  final int total;
  final DateTime? lastSyncedAt;
  final String? lastError;
  final List<String> errorLog;
  final bool isProcessing;

  const SyncStatusSnapshot({
    required this.status,
    required this.processed,
    required this.total,
    required this.lastSyncedAt,
    required this.lastError,
    required this.errorLog,
    required this.isProcessing,
  });

  double get progress => total == 0 ? 1.0 : (processed / total).clamp(0.0, 1.0);

  bool get hasError => lastError != null && lastError!.isNotEmpty;

  SyncStatusSnapshot copyWith({
    SyncStatus? status,
    int? processed,
    int? total,
    DateTime? lastSyncedAt,
    String? lastError,
    List<String>? errorLog,
    bool? isProcessing,
  }) {
    return SyncStatusSnapshot(
      status: status ?? this.status,
      processed: processed ?? this.processed,
      total: total ?? this.total,
      lastSyncedAt: lastSyncedAt ?? this.lastSyncedAt,
      lastError: lastError ?? this.lastError,
      errorLog: errorLog ?? this.errorLog,
      isProcessing: isProcessing ?? this.isProcessing,
    );
  }

  static SyncStatusSnapshot initial() => const SyncStatusSnapshot(
    status: SyncStatus.success,
    processed: 0,
    total: 0,
    lastSyncedAt: null,
    lastError: null,
    errorLog: <String>[],
    isProcessing: false,
  );
}

