  AnnotationMarker({
    required this.id,
    required this.type,
    required this.position,
    required this.color,
    this.strokeWidth = 3.0,
    this.label,
    this.text,
    this.direction,
    this.size,
    DateTime? createdAt,
  }) : createdAt = createdAt ?? DateTime.now();

  Map<String, dynamic> toJson() => {
        'id': id,
        'type': type.name,
        'position': {'dx': position.dx, 'dy': position.dy},
        'color': color.value,
        'strokeWidth': strokeWidth,
        'label': label,
        'text': text,
        'direction': direction,
        'size': size != null ? {'width': size!.width, 'height': size!.height} : null,
        'createdAt': createdAt.toIso8601String(),
      };

  static AnnotationMarker fromJson(Map<String, dynamic> json) {
    return AnnotationMarker(
      id: json['id'] as String,
      type: AnnotationType.values.firstWhere((value) => value.name == json['type']),
      position: Offset((json['position']['dx'] as num).toDouble(), (json['position']['dy'] as num).toDouble()),
      color: Color(json['color'] as int),
      strokeWidth: (json['strokeWidth'] as num?)?.toDouble() ?? 3.0,
      label: json['label'] as String?,
      text: json['text'] as String?,
      direction: (json['direction'] as num?)?.toDouble(),
      size: json['size'] != null
          ? Size((json['size']['width'] as num).toDouble(), (json['size']['height'] as num).toDouble())
          : null,
      createdAt: DateTime.parse(json['createdAt'] as String),
    );
  }

  AnnotationMarker copyWith({
    String? id,
    AnnotationType? type,
    Offset? position,
    Color? color,
    double? strokeWidth,
    String? label,
    String? text,
    double? direction,
    Size? size,
  }) {
    return AnnotationMarker(
      id: id ?? this.id,
      type: type ?? this.type,
      position: position ?? this.position,
      color: color ?? this.color,
      strokeWidth: strokeWidth ?? this.strokeWidth,
      label: label ?? this.label,
      text: text ?? this.text,
      direction: direction ?? this.direction,
      size: size ?? this.size,
      createdAt: createdAt,
    );
  }
}

