      ..style = PaintingStyle.fill;
    final strokePaint = Paint()
      ..color = Colors.white
      ..strokeWidth = annotation.strokeWidth + 2
      ..style = PaintingStyle.stroke;
    final position = Offset(
      annotation.position.dx * imageWidth,
      annotation.position.dy * imageHeight,
    );
    switch (annotation.type) {
      case AnnotationType.point:
        canvas.drawCircle(position, 8, strokePaint);
        canvas.drawCircle(position, 6, paint);
        break;
      case AnnotationType.arrow:
        _drawArrow(canvas, position, annotation.direction ?? 0, paint, strokePaint);
        break;
      case AnnotationType.rectangle:
        if (annotation.size != null) {
          final rect = Rect.fromCenter(
            center: position,
            width: annotation.size!.width * imageWidth,
            height: annotation.size!.height * imageHeight,
          );
          canvas.drawRect(rect, strokePaint);
          canvas.drawRect(rect, paint..style = PaintingStyle.stroke);
        }
        break;
      case AnnotationType.circle:
        final radius = (annotation.size?.width ?? 0.05) * imageWidth / 2;
