  bool _validateCoordinates(List<double> coordinates) {
    if (coordinates.isEmpty) {
      return false;
    }
    for (var i = 0; i < coordinates.length; i += 2) {
      final x = coordinates[i];
      final yIndex = i + 1;
      if (yIndex < coordinates.length) {
        final y = coordinates[yIndex];
        if (!_coordinateNormalizer.isValid(normalizedX: x, normalizedY: y)) {
          return false;
        }
      } else {
        if (x < 0.0 || x > 1.0) {
          return false;
        }
      }
    }
    return true;
  }

  Annotation? _findAnnotationAt(List<double> touchPoint, double tolerance) {
    if (touchPoint.length < 2) {
      return null;
    }
    final x = touchPoint[0];
    final y = touchPoint[1];
    for (var i = _annotations.length - 1; i >= 0; i--) {
      final annotation = _annotations[i];
      if (!annotation.isMobileLayer) {
        continue;
      }
      if (_hitTestAnnotation(annotation, x, y, tolerance)) {
        return annotation;
      }
    }
    return null;
  }

  bool _hitTestAnnotation(Annotation annotation, double x, double y, double tolerance) {
    final coords = annotation.coordinates;
    switch (annotation.toolType) {
      case AnnotationToolType.circle:
        if (coords.length < 3) return false;
        final dx = coords[0] - x;
        final dy = coords[1] - y;
        final radius = coords[2];
        return math.sqrt(dx * dx + dy * dy) <= radius + tolerance;
      case AnnotationToolType.arrow:
      case AnnotationToolType.line:
        if (coords.length < 4) return false;
        final startX = coords[0];
        final startY = coords[1];
        final endX = coords[2];
        final endY = coords[3];
        final minX = math.min(startX, endX) - tolerance;
        final maxX = math.max(startX, endX) + tolerance;
        final minY = math.min(startY, endY) - tolerance;
        final maxY = math.max(startY, endY) + tolerance;
        return x >= minX && x <= maxX && y >= minY && y <= maxY;
      case AnnotationToolType.freehand:
        if (coords.length < 4) return false;
        for (var i = 0; i < coords.length; i += 2) {
          final dx = coords[i] - x;
          final dy = coords[i + 1] - y;
          if (math.sqrt(dx * dx + dy * dy) <= tolerance) {
            return true;
          }
        }
        return false;
      case AnnotationToolType.text:
        if (coords.length < 2) return false;
        final dx = coords[0] - x;
        final dy = coords[1] - y;
        return math.sqrt(dx * dx + dy * dy) <= tolerance;
      case AnnotationToolType.eraser:
        return false;
    }
  }

