  Future<T> _executeWithBackoff<T>(Future<T> Function() action) async {
    const delays = [1, 2, 4, 8, 16];
    for (var attempt = 0; attempt < delays.length; attempt++) {
      try {
        return await action();
      } catch (error) {
        if (attempt == delays.length - 1) {
          rethrow;
        }
        final baseMs = (delays[attempt] * 1000).clamp(0, 30000);
        final jitterMs = _random.nextInt(250);
        await Future.delayed(Duration(milliseconds: baseMs + jitterMs));
      }
    }
    throw StateError('Backoff execution failed unexpectedly');
  }
