  /// Get annotation at position
  AnnotationMarker? getAnnotationAtPosition(Offset position) {
    if (_imageSize == null) return null;

    final normalizedPosition = Offset(
      position.dx / _imageSize!.width,
      position.dy / _imageSize!.height,
    );

    // Check annotations in reverse order (most recent first)
    for (int i = _annotations.length - 1; i >= 0; i--) {
      final annotation = _annotations[i];
      if (_isPositionInAnnotation(normalizedPosition, annotation)) {
        return annotation;
      }
    }

    return null;
  }

  /// Check if position is within annotation bounds
  bool _isPositionInAnnotation(Offset position, AnnotationMarker annotation) {
    const hitRadius = 0.02; // 2% of image size for hit detection

    switch (annotation.type) {
      case AnnotationType.point:
        final distance = (position - annotation.position).distance;
        return distance <= hitRadius;

      case AnnotationType.rectangle:
        if (annotation.size == null) return false;
        final rect = Rect.fromCenter(
          center: annotation.position,
          width: annotation.size!.width,
          height: annotation.size!.height,
        );
        return rect.contains(position);

      case AnnotationType.circle:
        if (annotation.size == null) return false;
        final distance = (position - annotation.position).distance;
        return distance <= annotation.size!.width / 2;

      case AnnotationType.arrow:
      case AnnotationType.text:
        final distance = (position - annotation.position).distance;
        return distance <= hitRadius;
    }
  }

  /// Convert normalized coordinates to screen coordinates
  Offset normalizedToScreen(Offset normalized) {
    if (_imageSize == null) return Offset.zero;
    return Offset(
